253→void ALFPWorldMapPlayerController::OnCancelAction(const FInputActionValue& Value)
254→{
255→	// 取消选中和可达高亮
256→	ClearReachableHighlight();
257→	if (SelectedNode)
258→	{
259→		SelectedNode->SetHighlighted(false);
260→		SelectedNode = nullptr;
261→	}
262→}
263→
264→void ALFPWorldMapPlayerController::OnToggleEditorAction(const FInputActionValue& Value)
265→{
266→	if (!WorldMapEditorComponent) return;
267→
268→	WorldMapEditorComponent->ToggleEditorMode();
269→
270→	if (WorldMapEditorComponent->IsEditorActive())
271→	{
272→		// 创建或显示编辑器 Widget
273→		if (!WorldMapEditorWidget && WorldMapEditorWidgetClass)
274→		{
275→			WorldMapEditorWidget = CreateWidget<ULFPWorldMapEditorWidget>(this, WorldMapEditorWidgetClass);
276→			if (WorldMapEditorWidget)
277→			{
278→				WorldMapEditorWidget->AddToViewport();
279→				WorldMapEditorWidget->InitializeEditor(WorldMapEditorComponent);
280→			}
281→		}
282→		else if (WorldMapEditorWidget)
283→		{
284→			WorldMapEditorWidget->SetVisibility(ESlateVisibility::Visible);
285→		}
286→
287→		bShowMouseCursor = true;
288→	}
289→	else
290→	{
291→		// 隐藏编辑器 Widget
292→		if (WorldMapEditorWidget)
293→		{
294→			WorldMapEditorWidget->SetVisibility(ESlateVisibility::Collapsed);
295→		}
296→	}
297→}
