299→// ============== 相机操作 ==============
300→
301→void ALFPWorldMapPlayerController::OnCameraPan(const FInputActionValue& Value)
302→{
303→	FVector2D PanInput = Value.Get<FVector2D>();
304→	CameraOffset += FVector(PanInput.X, PanInput.Y, 0) * CameraPanSpeed * GetWorld()->GetDeltaSeconds();
305→}
306→
307→void ALFPWorldMapPlayerController::OnCameraDragStarted(const FInputActionValue& Value)
308→{
309→	bIsDragging = true;
310→	DragTime = 0.f;
311→	GetMousePosition(DragStartPosition.X, DragStartPosition.Y);
312→}
313→
314→void ALFPWorldMapPlayerController::OnCameraDragTriggered(const FInputActionValue& Value)
315→{
316→	if (!bIsDragging) return;
317→
318→	FVector2D CurrentMousePos;
319→	GetMousePosition(CurrentMousePos.X, CurrentMousePos.Y);
320→	FVector2D Delta = CurrentMousePos - DragStartPosition;
321→
322→	CameraOffset -= FVector(-Delta.Y, Delta.X, 0) * CameraDragSpeed;
323→	DragStartPosition = CurrentMousePos;
324→}
325→
326→void ALFPWorldMapPlayerController::OnCameraDragCompleted(const FInputActionValue& Value)
327→{
328→	bIsDragging = false;
329→}
330→
331→void ALFPWorldMapPlayerController::OnCameraZoom(const FInputActionValue& Value)
332→{
333→	float ZoomDelta = Value.Get<float>();
334→	CurrentZoom = FMath::Clamp(CurrentZoom - ZoomDelta * CameraZoomSpeed, MinZoomDistance, MaxZoomDistance);
335→
336→	// 应用缩放到相机
337→	if (APlayerCameraManager* CameraManager = PlayerCameraManager)
338→	{
339→		FVector CameraLocation = CameraManager->GetCameraLocation();
340→		CameraLocation.Z = CurrentZoom;
341→		CameraManager->SetManualCameraFade(0.f, FLinearColor::Black, false);
342→	}
343→}
344→
345→// ============== 节点交互 ==============
346→
347→void ALFPWorldMapPlayerController::SelectNode(ALFPWorldMapNode* Node)
348→{
349→	// 取消之前的选中
350→	if (SelectedNode)
351→	{
352→		SelectedNode->SetHighlighted(false);
353→	}
354→
355→	SelectedNode = Node;
356→
357→	if (SelectedNode)
358→	{
359→		SelectedNode->SetHighlighted(true);
360→	}
361→}
362→
363→void ALFPWorldMapPlayerController::MoveToNode(ALFPWorldMapNode* Node)
364→{
365→	if (!Node) return;
366→
367→	ALFPWorldMapManager* Manager = GetWorldMapManager();
368→	if (!Manager) return;
369→
370→	// 棋子移动中不允许操作
371→	if (Manager->IsPawnMoving()) return;
372→
373→	ClearReachableHighlight();
374→
375→	// 记录目标节点，移动完成后自动进入
376→	PendingEnterNode = Node;
377→
378→	// 绑定棋子移动完成回调
379→	if (ALFPWorldMapPawn* MapPawn = Manager->GetPlayerPawn())
380→	{
381→		MapPawn->OnMoveComplete.AddUniqueDynamic(this, &ALFPWorldMapPlayerController::OnPawnMoveCompleted);
382→	}
383→
384→	bool bMoved = Manager->MovePlayer(Node->NodeID);
385→	if (!bMoved)
386→	{
387→		PendingEnterNode = nullptr;
388→	}
389→}
390→
391→void ALFPWorldMapPlayerController::ShowReachableNodes()
392→{
393→	ClearReachableHighlight();
394→
395→	ALFPWorldMapManager* Manager = GetWorldMapManager();
396→	if (!Manager || !Manager->GetPlayerState()) return;
397→
398→	TArray<int32> ReachableIDs = Manager->GetPlayerState()->GetReachableNodeIDs(Manager);
399→	for (int32 NodeID : ReachableIDs)
400→	{
401→		if (ALFPWorldMapNode* Node = Manager->GetNode(NodeID))
402→		{
403→			Node->SetHighlighted(true);
404→			ReachableNodes.Add(Node);
405→		}
406→	}
407→}
408→
409→void ALFPWorldMapPlayerController::ClearReachableHighlight()
410→{
411→	for (ALFPWorldMapNode* Node : ReachableNodes)
412→	{
413→		if (Node)
414→		{
415→			Node->SetHighlighted(false);
416→		}
417→	}
418→	ReachableNodes.Empty();
419→}
