202→void ULFPUnitMergeWidget::UpdatePreview()
203→{
204→	bool bCanMerge = false;
205→	SelectedEvolutionTarget = NAME_None;
206→
207→	// 清空进化目标展示
208→	if (Box_EvolutionChoices) Box_EvolutionChoices->ClearChildren();
209→	EvolutionChoiceButtons.Empty();
210→	EvolutionButtonToTargetMap.Empty();
211→
212→	if (!SlotA.bIsEmpty && !SlotB.bIsEmpty && CachedRegistry)
213→	{
214→		if (SlotA.Unit.TypeID == SlotB.Unit.TypeID)
215→		{
216→			TArray<FName> Targets = CachedRegistry->GetEvolutionTargets(SlotA.Unit.TypeID);
217→
218→			if (Targets.Num() >= 1)
219→			{
220→				// 为每个进化目标创建图标按钮
221→				for (const FName& TargetID : Targets)
222→				{
223→					FLFPUnitRegistryEntry TargetEntry;
224→					if (!CachedRegistry->FindEntry(TargetID, TargetEntry)) continue;
225→
226→					UButton* ChoiceBtn = NewObject<UButton>(this);
227→					if (!ChoiceBtn || !Box_EvolutionChoices) continue;
228→
229→					EvolutionChoiceButtons.Add(ChoiceBtn);
230→					EvolutionButtonToTargetMap.Add(ChoiceBtn, TargetID);
231→
232→					UHorizontalBoxSlot* BoxSlot = Box_EvolutionChoices->AddChildToHorizontalBox(ChoiceBtn);
233→					if (BoxSlot)
234→					{
235→						BoxSlot->SetPadding(FMargin(30.f));
236→						BoxSlot->SetHorizontalAlignment(HAlign_Center);
237→						BoxSlot->SetSize(FSlateChildSize(ESlateSizeRule::Fill));
238→					}
239→
240→					if (TargetEntry.Icon)
241→					{
242→						FButtonStyle Style = ChoiceBtn->GetStyle();
243→						Style.Hovered.SetResourceObject(TargetEntry.Icon);
244→						Style.Hovered.ImageSize = FVector2D(220.f, 80.f);
245→
246→						if (Targets.Num() == 1)
247→						{
248→							// 单目标：三态一致，看起来不像按钮
249→							Style.Normal = Style.Hovered;
250→							Style.Pressed = Style.Hovered;
251→						}
252→						else
253→						{
254→							Style.Normal.SetResourceObject(TargetEntry.Icon);
255→							Style.Normal.ImageSize = FVector2D(220.f, 80.f);
256→							Style.Pressed.SetResourceObject(TargetEntry.Icon);
257→							Style.Pressed.ImageSize = FVector2D(220.f, 80.f);
258→						}
259→
260→						ChoiceBtn->SetStyle(Style);
261→					}
262→
263→					// 多目标时需要点击选择
264→					if (Targets.Num() > 1)
265→					{
266→						ChoiceBtn->OnClicked.AddDynamic(this, &ULFPUnitMergeWidget::OnEvolutionChoiceClicked);
267→					}
268→				}
269→
270→				if (Targets.Num() == 1)
271→				{
272→					// 唯一目标 → 自动选中，直接可合并
273→					SelectedEvolutionTarget = Targets[0];
274→					bCanMerge = true;
275→
276→					FLFPUnitRegistryEntry TargetEntry;
277→					if (CachedRegistry->FindEntry(SelectedEvolutionTarget, TargetEntry) && Text_PreviewName)
278→					{
279→						FString PreviewText = FString::Printf(TEXT("%s %s"),
280→							*TargetEntry.DisplayName.ToString(), *MakeTierStars(TargetEntry.Tier));
281→						Text_PreviewName->SetText(FText::FromString(PreviewText));
282→					}
283→				}
284→				else
285→				{
286→					// 多目标 → 等待玩家选择
287→					if (Text_PreviewName)
288→					{
289→						Text_PreviewName->SetText(FText::FromString(TEXT("请选择进化方向")));
290→					}
291→				}
292→			}
293→			else
294→			{
295→				// 无进化目标（终阶）
296→				if (Text_PreviewName)
297→				{
298→					Text_PreviewName->SetText(FText::FromString(TEXT("已达终阶")));
299→				}
300→			}
301→		}
302→		else
303→		{
304→			if (Text_PreviewName)
305→			{
306→				Text_PreviewName->SetText(FText::FromString(TEXT("无法合并")));
307→			}
308→		}
309→	}
310→	else
311→	{
312→		if (Text_PreviewName)
313→		{
314→			Text_PreviewName->SetText(FText::FromString(TEXT("请选择两个相同单位")));
315→		}
316→	}
317→
318→	if (Button_Merge)
319→	{
320→		Button_Merge->SetIsEnabled(bCanMerge);
321→	}
322→}
