212→void ULFPSkillButtonWidget::UpdateCooldownDisplay()
213→{
214→    if (!CooldownText || !AssociatedSkill) return;
215→
216→    if (AssociatedSkill->CurrentCooldown > 0)
217→    {
218→        // 显示冷却信息
219→        FString CooldownString = FString::Printf(TEXT("%d"), AssociatedSkill->CurrentCooldown);
220→        CooldownText->SetText(FText::FromString(CooldownString));
221→        CooldownText->SetVisibility(ESlateVisibility::HitTestInvisible);
222→        CooldownText->SetColorAndOpacity(CooldownTextColor);
223→    }
224→    else if (AssociatedSkill->CooldownRounds > 0)
225→    {
226→        // 显示冷却回合数（当前不在冷却中）
227→        FString CooldownString = FString::Printf(TEXT("%dR"), AssociatedSkill->CooldownRounds);
228→        CooldownText->SetText(FText::FromString(CooldownString));
229→        CooldownText->SetVisibility(ESlateVisibility::HitTestInvisible);
230→        CooldownText->SetColorAndOpacity(AvailableTextColor);
231→    }
232→    else
233→    {
234→        // 无冷却，隐藏冷却文本
235→        CooldownText->SetVisibility(ESlateVisibility::Collapsed);
236→    }
237→}
