 41→void ULFPSkillSelectionWidget::InitializeSkillsInfo(ALFPTacticsUnit* Unit, ALFPTacticsPlayerController* PC)
 42→{
 43→    if (!Unit || !PC || !SkillGrid) return;
 44→
 45→    OwnerUnit = Unit;
 46→    TacticsPC = PC;
 47→
 48→    // 绑定阵营 AP 变化委托（先移除旧绑定，避免重复添加触发断言）
 49→    if (ALFPTurnManager* TurnManager = Unit->GetTurnManager())
 50→    {
 51→        TurnManager->OnFactionAPChanged.RemoveDynamic(this, &ULFPSkillSelectionWidget::OnFactionAPChanged);
 52→        TurnManager->OnFactionAPChanged.AddDynamic(this, &ULFPSkillSelectionWidget::OnFactionAPChanged);
 53→    }
 54→
 55→    // 清空所有技能按钮
 56→    SkillGrid->ClearChildren();
 57→    SkillButtons.Empty();
 58→
 59→    // 更新单位信息
 60→    UpdateUnitInfo();
 61→
 62→    // 获取可用技能
 63→    TArray<ULFPSkillBase*> AvailableSkills = Unit->GetAvailableSkills();
 64→
 65→    // 创建技能按钮
 66→    int32 Row = 0;
 67→    int32 Column = 0;
 68→
 69→    for (ULFPSkillBase* Skill : AvailableSkills)
 70→    {
 71→        if (!Skill) continue;
 72→
 73→        // 创建技能按钮
 74→        if (SkillButtonClass)
 75→        {
 76→            ULFPSkillButtonWidget* SkillButton = CreateWidget<ULFPSkillButtonWidget>(this, SkillButtonClass);
 77→            if (SkillButton)
 78→            {
 79→                // 初始化按钮
 80→                SkillButton->Initialize(Skill);
 81→                SkillButton->OwnerUnit = OwnerUnit;
 82→                SkillButton->TacticsPC = TacticsPC;
 83→                // 绑定点击事件
 84→                //SkillButton->OnSkillSelected.AddDynamic(this, &ULFPSkillSelectionWidget::OnSkillSelected);
 85→
 86→                // 添加到网格
 87→                SkillGrid->AddChildToUniformGrid(SkillButton, Row, Column);
 88→                SkillButtons.Add(SkillButton);
 89→
 90→                // 更新网格位置
 91→                Column++;
 92→                if (Column >= MaxColumns)
 93→                {
 94→                    Column = 0;
 95→                    Row++;
 96→                }
 97→            }
 98→        }
 99→    }
100→
101→    //// 如果没有可用技能，显示提示
102→    //if (AvailableSkills.Num() == 0)
103→    //{
104→    //    if (NoSkillsText)
105→    //    {
106→    //        NoSkillsText->SetVisibility(ESlateVisibility::Visible);
107→    //        NoSkillsText->SetText(FText::FromString("没有可用技能"));
108→    //    }
109→    //}
110→    //else
111→    //{
112→    //    if (NoSkillsText)
113→    //    {
114→    //        NoSkillsText->SetVisibility(ESlateVisibility::Collapsed);
115→    //    }
116→    //}
117→}
