141→void ULFPSkillSelectionWidget::UpdateSkillDetails(ULFPSkillBase* Skill)
142→{
143→    if (!Skill || !SkillNameText || !SkillDescriptionText || !SkillRangeText ||
144→        !SkillCooldownText)
145→    {
146→        return;
147→    }
148→
149→    // 更新技能信息
150→    SkillNameText->SetText(Skill->SkillName);
151→    SkillDescriptionText->SetText(Skill->SkillDescription);
152→
153→    //// 设置技能图标
154→    //if (Skill->SkillIcon)
155→    //{
156→    //    SkillIcon->SetBrushFromTexture(Skill->SkillIcon);
157→    //    SkillIcon->SetVisibility(ESlateVisibility::Visible);
158→    //}
159→    //else
160→    //{
161→    //    SkillIcon->SetVisibility(ESlateVisibility::Collapsed);
162→    //}
163→
164→    // 更新技能范围信息
165→    FString RangeText = FString::Printf(TEXT("范围: %d-%d"),
166→        Skill->Range.MinRange, Skill->Range.MaxRange);
167→
168→    if (Skill->Range.bRequireLineOfSight)
169→    {
170→        RangeText += TEXT(" (需要视线)");
171→    }
172→
173→    SkillRangeText->SetText(FText::FromString(RangeText));
174→
175→    // 更新冷却信息
176→    FString CooldownText;
177→    if (Skill->CooldownRounds > 0)
178→    {
179→        if (Skill->CurrentCooldown > 0)
180→        {
181→            CooldownText = FString::Printf(TEXT("CD: %d/%dRound"),
182→                Skill->CurrentCooldown, Skill->CooldownRounds);
183→        }
184→        else
185→        {
186→            CooldownText = FString::Printf(TEXT("CD: %dRound"), Skill->CooldownRounds);
187→        }
188→    }
189→    else
190→    {
191→        CooldownText = TEXT("No CD");
192→    }
193→
194→    SkillCooldownText->SetText(FText::FromString(CooldownText));
195→
196→    // 更新行动力消耗
197→    FString APText = FString::Printf(TEXT("Consume: %dAP"), Skill->ActionPointCost);
198→
199→    // 更新确认按钮状态
200→    UpdateConfirmButtonState();
201→}
