295→void ULFPSkillSelectionWidget::RefreshSkillButtons()
296→{
297→    if (!OwnerUnit) return;
298→
299→    // 更新单位信息
300→    UpdateUnitInfo();
301→
302→    // 刷新所有技能按钮状态
303→    for (ULFPSkillButtonWidget* Button : SkillButtons)
304→    {
305→        if (Button)
306→        {
307→            Button->RefreshState();
308→        }
309→    }
310→
311→    // 如果当前有选中的技能，更新其详情
312→    if (SelectedSkill)
313→    {
314→        UpdateSkillDetails(SelectedSkill);
315→    }
316→}
