318→FReply ULFPSkillSelectionWidget::NativeOnKeyDown(const FGeometry& InGeometry, const FKeyEvent& InKeyEvent)
319→{
320→    // 处理键盘输入
321→    if (InKeyEvent.GetKey() == EKeys::Escape)
322→    {
323→        OnCancelClicked();
324→        return FReply::Handled();
325→    }
326→    else if (InKeyEvent.GetKey() == EKeys::Enter || InKeyEvent.GetKey() == EKeys::SpaceBar)
327→    {
328→        OnConfirmClicked();
329→        return FReply::Handled();
330→    }
331→
332→    return Super::NativeOnKeyDown(InGeometry, InKeyEvent);
333→}
