335→void ULFPSkillSelectionWidget::NativeTick(const FGeometry& MyGeometry, float InDeltaTime)
336→{
337→    Super::NativeTick(MyGeometry, InDeltaTime);
338→
339→    // 定期刷新技能按钮状态（降低频率）
340→    static float RefreshTimer = 0.0f;
341→    RefreshTimer += InDeltaTime;
342→
343→    if (RefreshTimer >= 0.5f) // 每0.5秒刷新一次
344→    {
345→        RefreshTimer = 0.0f;
346→        RefreshSkillButtons();
347→    }
348→}
